// Çoxsaylı tip parametrləri
class Pair<K, V> {
  key: K;
  value: V;
  constructor(key: K, value: V) {
    this.key = key;
    this.value = value;
  }
  getPair(): [K, V] {
    return [this.key, this.value];
  }
}

let numberStringPair = new Pair<number, string>(1, 'one');
let stringBooleanPair = new Pair<string, boolean>('active', true);

console.log(numberStringPair.getPair()); // [1, 'one']
console.log(stringBooleanPair.getPair()); // ['active', true]
// let errorPair = new Pair<number, string>('test', 'test'); // Xəta: 'test' number tipinə uyğun deyil

// Generic sinif ilə generic interfeys
interface Container<T> {
  content: T;
  getContent(): T;
}

class Box<T> implements Container<T> {
  content: T;
  constructor(content: T) {
    this.content = content;
  }
  getContent(): T {
    return this.content;
  }
}

let stringBox = new Box<string>('Hello');
console.log(stringBox.getContent()); // Hello
// let errorBox = new Box<number>('test'); // Xəta: 'test' number tipinə uyğun deyil

// Generic sinif ilə tip aliası
type Item<T> = {
  value: T;
};

class ItemBox<T> {
  item: Item<T>;
  constructor(value: T) {
    this.item = { value };
  }
  getValue(): T {
    return this.item.value;
  }
}

let stringItemBox = new ItemBox<string>('Test');
console.log(stringItemBox.getValue()); // Test
// let errorItemBox = new ItemBox<number>('test'); // Xəta: 'test' number tipinə uyğun deyil

// Generic məhdudiyyət nümunəsi
class LengthBox<T extends { length: number }> {
  content: T;
  constructor(content: T) {
    this.content = content;
  }
  getLength(): number {
    return this.content.length;
  }
}

let stringBox = new LengthBox<string>('Hello');
let arrayBox = new LengthBox<number[]>([1, 2, 3]);

console.log(stringBox.getLength()); // 5
console.log(arrayBox.getLength()); // 3
// let errorBox = new LengthBox<number>(42); // Xəta: 42 length xüsusiyyətinə malik deyil

// Təhlükəsizlik nümunəsi
class KeyedBox<T, K extends keyof T> {
  data: T;
  constructor(data: T) {
    this.data = data;
  }
  getProperty(key: K): T[K] {
    return this.data[key];
  }
}

let personBox = new KeyedBox<{ name: string; age: number }>({ name: 'Alice', age: 30 });

console.log(personBox.getProperty('name')); // Alice
console.log(personBox.getProperty('age')); // 30
// console.log(personBox.getProperty('address')); // Xəta: 'address' mövcud deyil

// Səhvə yol açan nümunə
class UnsafeBox {
  content: any;
  constructor(content: any) {
    this.content = content;
  }
  getContent(): any {
    return this.content;
  }
}

let unsafeBox = new UnsafeBox('Hello');
console.log(unsafeBox.getContent()); // Hello, lakin tip təhlükəsizliyi yoxdur
unsafeBox = new UnsafeBox(42); // Keçərlidir, lakin təhlükəsiz deyil

